exercise.solutionCode:
function applyDiscount(price, discountPct = 10) {
    const discountAmount = price * discountPct / 100;
    const finalPrice     = price - discountAmount;
    return { original: price, discountAmount, finalPrice };
}

const result1 = applyDiscount(2000);
console.log("Default 10%:", result1.original, result1.discountAmount, result1.finalPrice);

const result2 = applyDiscount(2000, 25);
console.log("Custom 25%:",  result2.original, result2.discountAmount, result2.finalPrice);
